create extension if not exists pgcrypto;
create table if not exists organizations (id uuid primary key default gen_random_uuid(), clerk_org_id text unique, name text, created_at timestamptz default now());
create table if not exists users (id uuid primary key default gen_random_uuid(), clerk_user_id text unique, email text, name text, created_at timestamptz default now());
create table if not exists artists (id uuid primary key default gen_random_uuid(), organization_id uuid references organizations(id), name text not null, slug text unique, biography text, country text, created_at timestamptz default now(), updated_at timestamptz default now());
create table if not exists releases (id uuid primary key default gen_random_uuid(), organization_id uuid references organizations(id), artist_id uuid references artists(id), title text not null, release_type text, status text default 'draft', upc text, artwork_r2_key text, release_date date, created_at timestamptz default now(), updated_at timestamptz default now());
create table if not exists tracks (id uuid primary key default gen_random_uuid(), organization_id uuid references organizations(id), release_id uuid references releases(id), artist_id uuid references artists(id), title text not null, version text, isrc text, track_number integer, duration_seconds integer, explicit boolean default false, audio_original_r2_key text, audio_master_r2_key text, audio_flac_r2_key text, loudness_lufs numeric, true_peak_db numeric, sample_rate integer, channels integer, status text default 'draft', created_at timestamptz default now(), updated_at timestamptz default now());
create table if not exists upload_jobs (id uuid primary key default gen_random_uuid(), organization_id uuid references organizations(id), track_id uuid references tracks(id), original_filename text, r2_key text, status text default 'pending', error_message text, created_at timestamptz default now(), updated_at timestamptz default now());
create table if not exists processing_jobs (id uuid primary key default gen_random_uuid(), organization_id uuid references organizations(id), track_id uuid references tracks(id), job_type text, status text default 'queued', input_r2_key text, output_r2_key text, log jsonb, error_message text, created_at timestamptz default now(), updated_at timestamptz default now());
